(994, 1309, 'دانشجوی انصرافی حسابداری گرایش حسابرسی سال ۹۰', 'دیپلم', 'علمی کاربردی_واحد دانه‌های روغنی', 1390, 0, 'بنا به دلایل شخصی و مالی مجبور به ترک تحصیل شدم،آشنایی کامل به نرم افزار نویان،هلو،رافع۶ متوسط،آشنایی به اکسل به ورد،فن بیان بالا و روابط اجتماعی بالا', '2022-01-31 19:28:12', '2022-01-31 19:28:12'),
(995, 1287, 'حسابداری', 'کارشناسی', 'دانشگاه آزاد تهران مرکز', NULL, 1, 'چند واحد از درسم مونده که چندسالی هست به علت مشکلات اقتصادی نرفتم به اتمام برسونم', '2022-01-31 21:06:15', '2022-01-31 21:06:15'),
(996, 1308, 'مدیریت بازرگانی', 'کارشناسی', 'پیام نور', 1393, 0, NULL, '2022-02-01 06:17:01', '2022-02-01 06:17:01'),
(997, 1312, 'حسابداری مالی', 'کارشناسی', 'آزاد', 1394, 0, 'آشنایی کامل با نرم افزار های حسابداری - انجام پروژه ای حسابداری شرکت ها و مشاغل مختلف از قبیل حسابداری.نقدینگی.انبارداری (بهای تمام شده).فروش.دارایی.حقوق و دستمزد\nنصب و راه اندازی , استقرار سیستم های حسابداری\nمسلط به تنظیم گزارشات فصلی و ارزش افزوده و ارسال به سازمان مربوطه\nمسلط به تنظیم لیست بیمه پرسنل، تنظیم لیست مالیات حقوق و ارسال به سازمان مربوطه\nنگهداری وراهبری سیستم های مکانیزه حقوق و دستمزد وثبت ماهانه اطلاعات لازم در آن و کاربری سایر سیستمهای نرم افزاری موجود .\nثبت بموقع دفاترقانونی (روزنامه وکل) براساس اسناد قطعی شده حسابداری یاخلاصه اسناد حسابداری تهیه شده از سیستم کامپیوتری ، مطابق آئین نامه ثبت ونگهداری دفاترقانونی مصوب وزارت اموراقتصادی ودارایی ، تهیه و ارائه اظهارنامه عملکرد اشخاص حقیقی و حقوقی\nارائه گزارش های جامع مدیریتی', '2022-02-01 06:20:55', '2022-02-06 13:06:24'),
(998, 1313, 'حسابداری', 'کاردانی', 'سازمان مدیریت صنعتی', 1394, 0, 'کاردانی کامپیوتر گرایش نرم افزار از دانشگاه سراسری گرگان واحد چمران\nدر رشته حسابداری در سطح کاردانی معرف حضور میگردد به دلیل عدم ارایه واحد های عمومی و سیاسی از طرف سازمان مدیریت صنعتی (زیرمجموعه سازمان گسترش صنایع) مورد تایید وزارت علوم نیست', '2022-02-01 08:03:52', '2022-02-01 08:03:52'),
