(3843, 6326, 'حسابداری', 'کارشناسی', 'غیر انتفاعی تابران', 1390, NULL, 'از دوم دبیرستان در هنرستان مشغول تحصیل حسابداری بودم', '2025-10-22 13:15:21', '2025-10-22 13:15:21'),
