(4605, 7537, 'حسابداری', 'کارشناسی', 'دانشگاه شریعتی تهران', 1402, NULL, NULL, '2025-12-08 16:48:12', '2025-12-08 16:48:12'),
(4606, 7540, 'مهندسی فناوری اطلاعات', 'کارشناسی', 'دانشگاه آزاد تهران شمال', 1399, NULL, 'دوره ‌های آموزشی:\nقوانین و مقررات بیمه و تامین اجتماعی موسسه آموزشی حسابداران خبره/پکت\n.\nهمایش قوانین و مقررات مالیاتی و قانون پایانه‌های فروشگاهی موسسه آموزشی حسابداران خبره/پکت\n.\nحسابداری بهای تمام شده_صنعتی موسسه آموزشی حسابداران خبره/پکت \n.\nدوره قوانین و مقررات دائمی مالیات بر ارزش افزوده موسسه آموزشی حسابداران خبره/پکت\n.\nدوره ترفندهای اکسل در حسابداری مجتمع فنی تهران/ونک\n.\nدوره حسابداری ویژه بازار کار( صفر تا صد)مجتمع فنی تهران/انقلاب', '2025-12-08 17:12:21', '2025-12-08 17:45:54'),
(4607, 7543, 'مدیریت مالی', 'کارشناسی ارشد', 'راهبرد شمال', 1398, NULL, NULL, '2025-12-08 17:25:47', '2025-12-08 17:25:47'),
(4608, 7541, 'مهندسی گیاه پزشکی', 'کارشناسی', 'دانشگاه آزاد اسلامی پردیس واحد شیراز', 1400, NULL, 'رشته دانشگاهیم مهندسی گیاه پزشکی است.\nو علاقه مند به رشته حسابداری هستم ورشته حسابداری را به صورت دوره های آموزشی مخصوص بازار کار آموزش دیده ام.', '2025-12-08 17:38:33', '2025-12-08 17:38:33'),
(4609, 7547, 'حسابداری مالی', 'کارشناسی', 'دانشگاه علمی کاربردی', 1404, NULL, NULL, '2025-12-08 20:13:35', '2025-12-08 20:13:35'),
(4610, 7546, 'کارشناسی حسابداری و ارشد مدیریت دولتی', 'کارشناسی ارشد', 'آزاد آبادان  و پیام نور تهران', 1397, NULL, 'لیسانس حسابداری دانشگاه آزاد آبادان. و. فوق لیسانس  دانشگاه پیام نور تهران مدیریت دولتی گرایش بودجه و مالیه عمومی', '2025-12-08 20:35:44', '2025-12-08 20:35:44'),
(4611, 6773, 'حسابداری', 'کارشناسی', 'دانشگاه شهید بهشتی تهران', 1403, NULL, 'کارشناسی حسابداری از دانشگاه شهید بهشتی تهران\nهمکاری و تسلط بر نحوه اخذ ضمانتنامه بانکی ، اعتبارات اسنادی و تسهیلات\nآشنایی به امور خزانه \nتجزیه و تحلیل اطلاعات، مسولیت پذیری بالا\nارتباطات کتبی و شفاهی \nپرداخت حقوق و دستمزد \nتسلط بر نرم افزار های حسابداری \nپیگیری مطالبات\nکار با بانکداری الکترونیکی \nصدور چک و ثبت در سامانه صیاد \nارتباط موثر با بانک ها \nمراجعه به بانک و ادارات در صورت نیاز \nتسلط کامل بر امور بیمه ای اخذ مفاصا حساب و ردیف پیمان و سایر امور پرسنلی \nاخلاق حرفه ای بالا', '2025-12-08 23:25:29', '2025-12-08 23:25:29'),
(4612, 7551, 'حسابداری', 'کارشناسی', '', 1399, NULL, NULL, '2025-12-08 23:30:43', '2025-12-08 23:30:43'),
(4613, 7552, 'حسابداری', 'کارشناسی ارشد', 'دانشگاه بین المللی خلیج فارس آبادان', 1395, NULL, 'دیپلم حسابداری خودم رو از هنرستان گرفتم. فوق دیپلم رو از دانشگاه دزفول و لیسانس رو از دانشگاه غیر انتفاعی یزد و فوق لیسانس رو از دانشگاه بین المللی خلیج فارس آبادان فارغ از تحصیل شدم.', '2025-12-09 00:19:49', '2025-12-09 00:19:49'),
(4614, 7555, 'حسابداری', 'کارشناسی', 'دانشگاه آزاد', NULL, 1, NULL, '2025-12-09 10:10:12', '2025-12-09 10:10:12'),
(4615, 4985, 'حسابداری مالی', 'کارشناسی', 'علمی کاربردی', 1394, NULL, 'کاردانی مدیریت کسب و کار\nکارشناسی حسابداری مالی\nکارشناسی ارشد مدیریت بازرگانی بین الملل', '2025-12-09 10:13:38', '2025-12-09 10:13:38'),
(4616, 7557, 'حسابداری', 'کاردانی', 'علمی کاربردی', 1384, NULL, NULL, '2025-12-09 10:18:47', '2025-12-09 10:18:47'),
(4617, 7558, 'مدیریت صنعتی', 'کارشناسی ارشد', 'فیروزکوه', 1397, NULL, NULL, '2025-12-09 10:21:42', '2025-12-09 10:21:42'),
(4618, 7560, 'حسابداری', 'کارشناسی', 'آزاد سبزوار', 1381, NULL, NULL, '2025-12-09 10:57:54', '2025-12-09 10:57:54'),
(4619, 7561, 'حسابرسی', 'کارشناسی ارشد', 'سناباد', 1401, NULL, 'کارشناسی ارشد در رشته حسابرسی \nلیسانس حسابداری\nمسلط به نرم افزارهای مالی\nگواهینامه ICDL', '2025-12-09 11:00:15', '2025-12-09 11:00:15'),
(4620, 7562, 'حسابداری', 'کارشناسی ارشد', 'آزاد اردبیل', 1396, NULL, 'دیپلم حسابداری سال ۸۷\nفوق دیپلم دانشگاه فنی سراسری سال ۸۹\nلیسانس حسابداری دانشگاه غیر انتفاعی سال ۹۱\nفوق لیسانس حسابداری دانشگاه آزاد سال ۹۶', '2025-12-09 11:03:44', '2025-12-09 11:03:44'),
(4621, 7565, 'حسابداری بازرگانی', 'کارشناسی', 'دانشگاه آزاد اسلامشهر', 1393, NULL, NULL, '2025-12-09 12:04:01', '2025-12-09 12:04:01'),
(4622, 7566, 'حسابداری', 'کارشناسی', 'دانشگاه گیلان', NULL, 1, NULL, '2025-12-09 12:25:33', '2025-12-09 12:25:33'),
(4624, 7569, 'حسابداري و مديريت', 'کارشناسی ارشد', 'مازندران', 1392, NULL, NULL, '2025-12-09 13:23:23', '2025-12-09 13:23:23'),
(4625, 7571, 'حسابداری', 'دکترا و بالاتر', 'دانشگاه علوم و تحقیقات تهران', 1399, NULL, 'اینجانب در سال ۱۳۸۰ لیسانس را از دانشگاه ملی تهران \nو در سال ۱۳۸۳ فوق لیسانس را از دانشگاه آزاد تهران مرکز \nو در سال ۱۳۹۹ دکترای تخصصی را از دانشگاه علوم و تحقیقات تهران دریافت کرده ام \nهر سه مقطع دانشگاهی در رشته حسابداری بوده است', '2025-12-09 13:46:54', '2025-12-09 13:46:54'),
(4626, 7574, 'حسابداری', 'کارشناسی', 'دانشگاه آزاد واحد قم', 1392, NULL, 'از مقطع دبیرستان تا کارشناسی فقط در رشته حسابداری تحصیل کرده ام.', '2025-12-09 13:53:49', '2025-12-09 13:53:49'),
